// ─── GHL Field Mapping ───────────────────────────────────────
// Mapa de campos TuAgenteStore → GoHighLevel
// Activar cuando se contrate GHL (Starter USD 97/mes recomendado)
// API Docs: https://highlevel.stoplight.io/docs/integrations/
//
// PARA ACTIVAR:
// 1. Contratar GHL en https://gohighlevel.com
// 2. Settings > Integrations > API > crear API Key
// 3. Agregar GHL_API_KEY al .env del VPS
// 4. Activar este workflow en n8n

const body = $input.first().json.body || $input.first().json;

const ghlContact = {
  firstName:    (body.name || '').split(' ')[0],
  lastName:     (body.name || '').split(' ').slice(1).join(' '),
  email:        body.email,
  phone:        body.whatsapp,
  companyName:  body.company,
  // Custom fields GHL
  customFields: [
    { id: 'problem_area',   field_value: body.problem_area },
    { id: 'budget_range',   field_value: body.budget_range },
    { id: 'company_size',   field_value: body.company_size },
    { id: 'channel_origin', field_value: body.channel_origin },
    { id: 'agent_interest', field_value: body.agent_interest || '' },
    { id: 'lead_source',    field_value: 'tuagentestore.com' }
  ],
  tags: ['tuagentestore', body.problem_area, body.channel_origin].filter(Boolean)
};

const ghlOpportunity = {
  title:       `[TAS] ${body.name} — ${body.problem_area}`,
  status:      'open',
  stageId:     'STAGE_ID_NUEVO',     // Reemplazar con ID real del pipeline stage
  pipelineId:  'PIPELINE_ID_VENTAS', // Reemplazar con ID real
  monetaryValue: 397,                // Ticket mínimo USD
  assignedTo:  'USER_ID_ADMIN'       // Reemplazar con ID del usuario GHL
};

return [{ json: { ...body, ghl_contact: ghlContact, ghl_opportunity: ghlOpportunity } }];

// Actualizar ghl_contact_id en TuAgenteStore DB (vía API interna)
const ghlResponse = $input.first().json;
const leadId = $('Mapear campos → GHL').first().json.lead_id;

if (!ghlResponse.contact?.id || !leadId) {
  return [{ json: { skipped: true, reason: 'No contact ID or lead ID' } }];
}

const res = await fetch(`${$env.NEXT_APP_URL || 'https://tuagentestore.com'}/api/admin/reservations/${leadId}`, {
  method: 'PATCH',
  headers: {
    'Content-Type': 'application/json',
    'x-webhook-secret': $env.WEBHOOK_SECRET_INTERNAL
  },
  body: JSON.stringify({ ghl_contact_id: ghlResponse.contact.id })
});

return [{ json: { ok: res.ok, ghl_contact_id: ghlResponse.contact?.id } }];
